mapper.select:
SELECT a.*, d.device_name FROM alarm_record a LEFT JOIN device d ON a.device_code = d.device_code WHERE 1=1

   AND a.project_id = #{projectId}


   AND d.model_id = #{modelId}


   AND a.device_code = #{deviceCode}


   AND a.alarm_rule_id = #{ruleId}


   AND a.alarm_level = #{alarmLevel}


   AND a.status = #{status}


   AND a.alarm_time >= #{startTime}


   AND a.alarm_time <= #{endTime}

 ORDER BY a.alarm_time DESC
